from flask import Flask, render_template, request
from markupsafe import escape
import html

app = Flask(__name__)

@app.route('/welcome')
def welcome_dashboard():
    # Get query parameters with default values
    user_name = request.args.get('name', 'User')
    user_bio = request.args.get('bio', '')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', 'No status message')
    
    # Sanitize the bio and status for HTML rendering
    sanitized_bio = html.escape(user_bio)
    sanitized_status = html.escape(user_status)
    
    # Render the dashboard with sanitized data
    return render_template('welcome.html', 
                         name=user_name,
                         bio=sanitized_bio,
                         location=user_location,
                         status=sanitized_status)

if __name__ == '__main__':
    app.run(debug=True)